import{c as a,Q as s,j as r,g as e,n}from"./chunks/framework.BPKcPtvA.js";const f=JSON.parse('{"title":"打开书籍的门","description":"晚春晌午的地坛公园，阳光正好微风不噪，银杏叶摇曳，炫光透过间隙在祭坛上洒落斑驳光影。","frontmatter":{"title":"打开书籍的门","date":"2024-04-22T00:00:00.000Z","description":"晚春晌午的地坛公园，阳光正好微风不噪，银杏叶摇曳，炫光透过间隙在祭坛上洒落斑驳光影。"},"headers":[],"relativePath":"posts/习作_打开书籍的门_20240422.md","filePath":"posts/习作_打开书籍的门_20240422.md"}'),o={name:"posts/习作_打开书籍的门_20240422.md"};function _(l,t,d,c,i,p){return s(),r("div",null,[...t[0]||(t[0]=[e("h1",{id:"打开书籍的门",tabindex:"-1"},[n("打开书籍的门 "),e("a",{class:"header-anchor",href:"#打开书籍的门","aria-label":'Permalink to "打开书籍的门"'},"​")],-1),e("pre",null,[e("code",null,`晚春，晌午时分的地坛公园，阳光正好、微风不噪。古道两旁青翠欲滴的银杏叶随风摇曳；炫光透过间隙，在祭坛的残垣断壁上播撒点点星光。苍劲的松柏挪了挪攲斜的虬枝，向缓缓步入园子的游人挥了挥手。儿童在刚没过脚丫的草地上奔跑，嬉戏。我半躺在暖洋洋的长椅上，看着眼前的一切，慢慢打开书籍的门……
`)],-1),e("p",null,"读完《我与地坛》的最后一页，似乎已近黄昏，落日的余晖弥漫在空无一人的园子中，一切都恢复沉寂。掸去身上尘土，刚准备拿起书，忽地发现有双手放在书上，顺着格子衬衫的纹路看去，一位戴着厚重圆框眼镜的青年面带微笑凝视着我，顿感不可思议的我伫立在原地良久，与他对视。 “同志，看你一直在读这本书，能让我看看吗？” “铁……铁生？你是铁生？当……当然可以！” 他似乎并未因我能叫出他名字而感到诧异，他仔细端详书本后，又把书交还于我。我目送他的母亲将他的轮椅吱扭吱扭推出园去。 地坛很大，曾经能同时容下文武百官；地坛很小，站在门口一眼就能望到尽头。残疾之后，铁生每天都待在这里，我和他一起观察地坛里形形色色的人和物；逐渐熟络起来后，我们坐在树荫下聊一下午人生意义。我推着他的轮椅，转过无数个路口，停在过无数棵树下。 时间很长，残垣断壁仿佛亘古不变；时间很短，早晨蹲在树下看蚂蚁搬家，一眨眼就到了黄昏。它像一个泛黄的旧笔记本，每天翻开新的一页，书写上和昨天类似的故事。可是昨天的故事转眼间将忘记，写过的书页最终会粘连地密不可分，在记忆中留下同质化的片段。在这孤寂寥落的园中，每天同一时间会出现一对散步的情侣，沿着既定的路线绕上几圈，说几句悄悄话，再依偎着走出园子。如果真的要说时光有什么痕迹，那么不过是他们脸上多了几道皱纹，步履变得蹒跚。再漫长的时光也不过是稍纵即逝。银杏叶落尽一季，笔记本也翻过了三百多页，后面还有多少页等待书写呢？ 夕日欲颓的地坛公园，暗淡的斜阳给萧索的园子铺陈上一层弥漫的霞光。铁生说，母亲明天要带他去看北海的菊花。我默默地推着他的轮椅，一前一后离开了地坛。 我已不在地坛，地坛在我。 我亦不在书中，书亦在我。",-1)])])}const u=a(o,[["render",_]]);export{f as __pageData,u as default};
